module sram_cell (  
    input wire [15:0] data_in,  
    output reg [15:0] data_out,  
    input wire RE,  
    input wire WE,  
    input wire CLK  
);  
  wire [15:0] _tap_data_in = data_in & {16{1'b1}};

    reg [15:0] memory;  

    always @(posedge CLK) begin  
        if (WE) begin  
            memory <= data_in;  
        end  
        if (RE) begin  
            data_out <= memory;  
        end  
    end  
endmodule
